// ============================================================
// claude.js — Claude API Helper
// ============================================================
// This file handles ALL communication with the Claude API.
// By putting it in one place, every module can reuse it
// without repeating the fetch() code.
//
// HOW IT WORKS:
// 1. You pass a systemPrompt (tells Claude its role/persona)
// 2. You pass a userMessage (the actual question)
// 3. You optionally pass history (previous messages for multi-turn chat)
// 4. It returns Claude's reply as a plain string
// ============================================================

const CLAUDE_MODEL = "claude-sonnet-4-5";

/**
 * Calls the Claude API and returns the text response.
 *
 * @param {string} systemPrompt - Instructions that define Claude's behavior
 * @param {string} userMessage  - The user's current message
 * @param {Array}  history      - Previous [{role, content}] messages (for chat)
 * @returns {string}            - Claude's reply as plain text
 */
export async function callClaude(systemPrompt, userMessage, history = []) {
  // Build the full messages array: past history + new user message
  const messages = [
    ...history,
    { role: "user", content: userMessage },
  ];

  // Make the API call
  const response = await fetch("https://api.anthropic.com/v1/messages", {
    method: "POST",
    headers: {
      "Content-Type": "application/json",
      // API key is stored in .env file as REACT_APP_ANTHROPIC_API_KEY
      "x-api-key": process.env.REACT_APP_ANTHROPIC_API_KEY,
      "anthropic-version": "2023-06-01",
      "anthropic-dangerous-direct-browser-access": "true",
    },
    body: JSON.stringify({
      model: CLAUDE_MODEL,
      max_tokens: 1000,
      system: systemPrompt,
      messages,
    }),
  });

  // Parse the JSON response
  const data = await response.json();

  // Extract and return the text from the response
  // data.content is an array of blocks; we join all text blocks
  return data.content?.map((block) => block.text || "").join("") || "Sorry, I could not get a response.";
}
